import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{r as l,o as d,c as i,a as t,e,b as c,d as a}from"./app-75fed8c6.js";const o="/img/study/linux/file.png",r="/img/study/linux/file2.png",p={},u=a(`<h2 id="文件权限" tabindex="-1"><a class="header-anchor" href="#文件权限" aria-hidden="true">#</a> 文件权限</h2><p>在 Linux 中我们可以使用 ll 或者 ls –l 命令来显示一个文件的属性以及文件所属的用户和组，如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@www /<span class="token punctuation">]</span><span class="token comment"># ls -l</span>
total <span class="token number">64</span>
dr-xr-xr-x   <span class="token number">2</span> root root <span class="token number">4096</span> Dec <span class="token number">14</span>  <span class="token number">2012</span> bin
dr-xr-xr-x   <span class="token number">4</span> root root <span class="token number">4096</span> Apr <span class="token number">19</span>  <span class="token number">2012</span> boot
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>实例中，bin 文件的第一个属性用 d 表示。d 在 Linux 中代表该文件是一个目录文件。</p><p>在 Linux 中第一个字符代表这个文件是目录、文件或链接文件等等。</p><ul><li>当为<code>d</code>则是目录</li><li>当为<code>-</code>则是文件；</li><li>若是<code>l</code>则表示为链接文档(link file)；</li><li>若是<code>b</code>则表示为装置文件里面的可供储存的接口设备(可随机存取装置)；</li><li>若是<code>c</code>则表示为装置文件里面的串行端口设备，例如键盘、鼠标(一次性读取装置)。</li></ul><p>接下来的字符中，以三个为一组，且均为<code>rwx</code>的三个参数的组合。其中，<code>r</code>代表可读(read)、<code>w</code>代表可写(write)、<code>x</code>代表可执行(execute)。 要注意的是，这三个权限的位置不会改变，如果没有权限，就会出现减号<code>-</code>而已。</p><figure><img src="`+o+'" alt=" " tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>每个文件的属性由左边第一部分的 10 个字符来确定（如下图）。</p><figure><img src="'+r+`" alt=" " tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="更改文件属性" tabindex="-1"><a class="header-anchor" href="#更改文件属性" aria-hidden="true">#</a> 更改文件属性</h2><h3 id="chgrp" tabindex="-1"><a class="header-anchor" href="#chgrp" aria-hidden="true">#</a> chgrp</h3><p>用于变更文件或目录的所属群组。</p><h4 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chgrp</span> <span class="token punctuation">[</span>-cfhRv<span class="token punctuation">]</span><span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>--version<span class="token punctuation">]</span><span class="token punctuation">[</span>所属群组<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录<span class="token punctuation">..</span>.<span class="token punctuation">]</span> 或 <span class="token function">chgrp</span> <span class="token punctuation">[</span>-cfhRv<span class="token punctuation">]</span><span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>--reference<span class="token operator">=</span><span class="token operator">&lt;</span>参考文件或目录<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--version<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-c</code>或<code>--changes</code>：效果类似&quot;-v&quot;参数，但仅回报更改的部分。</li><li><code>-f</code>或<code>--quiet 或 --silent</code>：不显示错误信息。</li><li><code>-h</code>或<code>--no-dereference</code>：只对符号连接的文件作修改，而不改动其他任何相关文件。</li><li><code>-R</code>或<code>--recursive</code>：递归处理，将指定目录下的所有文件及子目录一并处理。</li><li><code>-v</code>或<code>--verbose</code>：显示指令执行过程。</li><li><code>--help</code>：在线帮助。</li><li><code>--reference=&lt;参考文件或目录&gt;</code>：把指定文件或目录的所属群组全部设成和参考文件或目录的所属群组相同。</li><li><code>--version</code>：显示版本信息。</li></ul><h4 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h4><p>实例 1：改变文件的群组属性：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chgrp</span> <span class="token parameter variable">-v</span> bin log2012.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>输出：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@localhost test<span class="token punctuation">]</span><span class="token comment"># ll</span>
---xrw-r-- <span class="token number">1</span> root root <span class="token number">302108</span> <span class="token number">11</span>-13 06:03 log2012.log
<span class="token punctuation">[</span>root@localhost test<span class="token punctuation">]</span><span class="token comment"># chgrp -v bin log2012.log</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>&quot;log2012.log&quot; 的所属组已更改为 bin</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@localhost test<span class="token punctuation">]</span><span class="token comment"># ll</span>
---xrw-r-- <span class="token number">1</span> root bin  <span class="token number">302108</span> <span class="token number">11</span>-13 06:03 log2012.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="chown" tabindex="-1"><a class="header-anchor" href="#chown" aria-hidden="true">#</a> chown</h3><p>用于设置文件所有者和文件关联组的命令。</p><h4 id="语法-1" tabindex="-1"><a class="header-anchor" href="#语法-1" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chown</span> <span class="token punctuation">[</span>–R<span class="token punctuation">]</span> 所有者 文件名
<span class="token function">chown</span> <span class="token punctuation">[</span>-R<span class="token punctuation">]</span> 所有者:属组名 文件名
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>user</code>: 新的文件拥有者的使用者 ID</li><li><code>group</code>: 新的文件拥有者的使用者组(group)</li><li><code>-c</code>: 显示更改的部分的信息</li><li><code>-f</code>: 忽略错误信息</li><li><code>-h</code>:修复符号链接</li><li><code>-v</code>: 显示详细的处理信息</li><li><code>-R</code>: 处理指定目录以及其子目录下的所有文件</li><li><code>--help</code>: 显示辅助说明</li><li><code>--version</code>: 显示版本</li></ul><h4 id="实例-1" tabindex="-1"><a class="header-anchor" href="#实例-1" aria-hidden="true">#</a> 实例</h4><p>进入 /root 目录（~）将 install.log 的拥有者改为 bin 这个账号：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>root@www ~<span class="token punctuation">]</span> <span class="token builtin class-name">cd</span> ~
<span class="token punctuation">[</span>root@www ~<span class="token punctuation">]</span><span class="token comment"># chown bin install.log</span>
<span class="token punctuation">[</span>root@www ~<span class="token punctuation">]</span><span class="token comment"># ls -l</span>
-rw-r--r--  <span class="token number">1</span> bin  <span class="token function">users</span> <span class="token number">68495</span> Jun <span class="token number">25</span> 08:53 install.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="chmod" tabindex="-1"><a class="header-anchor" href="#chmod" aria-hidden="true">#</a> chmod</h3><p>控制用户对文件的权限的命令,Linux/Unix 的文件调用权限分为三级 : 文件所有者（Owner）、用户组（Group）、其它用户（Other Users）。只有文件所有者和超级用户可以修改文件或目录的权限。可以使用绝对模式（八进制数字模式），符号模式指定文件的权限。</p><h4 id="语法-2" tabindex="-1"><a class="header-anchor" href="#语法-2" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token punctuation">[</span>-cfvR<span class="token punctuation">]</span> <span class="token punctuation">[</span>--help<span class="token punctuation">]</span> <span class="token punctuation">[</span>--version<span class="token punctuation">]</span> mode file<span class="token punctuation">..</span>.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>mode : 权限设定字串，格式如下:<code>[ugoa...][[+-=][rwxX]...][,...]</code><ul><li><code>u</code>表示该文件的拥有者，<code>g</code>表示与该文件的拥有者属于同一个群体(group)者，<code>o</code>表示其他以外的人，<code>a</code>表示这三者皆是。</li><li><code>+</code>表示增加权限、<code>-</code>表示取消权限、<code>=</code>表示唯一设定权限。</li><li><code>r</code>表示可读取，<code>w</code>表示可写入，<code>x</code>表示可执行，<code>X</code>表示只有当该文件是个子目录或者该文件已经被设定过为可执行。</li></ul></li><li><code>-c</code>:若该文件权限确实已经更改，才显示其更改动作</li><li><code>-f</code>:若该文件权限无法被更改也不要显示错误讯息</li><li><code>-v</code>:显示权限变更的详细资料</li><li><code>-R</code>:对目前目录下的所有文件与子目录进行相同的权限变更(即以递归的方式逐个变更)</li><li><code>--help</code>:显示辅助说明</li><li><code>--version</code>:显示版本</li></ul><h4 id="符号模式" tabindex="-1"><a class="header-anchor" href="#符号模式" aria-hidden="true">#</a> 符号模式</h4><p>使用符号模式可以设置多个项目：<code>who</code>（用户类型），<code>operator</code>（操作符）和 <code>permission</code>（权限），每个项目的设置可以用逗号隔开。 命令<code>chmod</code>将修改<code>who</code>指定的用户类型对文件的访问权限，用户类型由一个或者多个字母<code>who</code>的位置来说明，如<code>who</code>的符号模式表所示:</p><table><thead><tr><th style="text-align:left;">who</th><th style="text-align:center;">用户类型</th><th style="text-align:center;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">u</td><td style="text-align:center;">user</td><td style="text-align:center;">文件所有者</td></tr><tr><td style="text-align:left;">g</td><td style="text-align:center;">group</td><td style="text-align:center;">文件所有者所在组</td></tr><tr><td style="text-align:left;">o</td><td style="text-align:center;">others</td><td style="text-align:center;">所有其他用户</td></tr><tr><td style="text-align:left;">a</td><td style="text-align:center;">all</td><td style="text-align:center;">所有用户, 相当于 ugo</td></tr></tbody></table><p>operator 的符号模式表:</p><table><thead><tr><th style="text-align:left;">who</th><th style="text-align:center;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">+</td><td style="text-align:center;">为指定的用户类型增加权限</td></tr><tr><td style="text-align:left;">-</td><td style="text-align:center;">去除指定用户类型的权限</td></tr><tr><td style="text-align:left;">=</td><td style="text-align:center;">设置指定用户权限的设置，即将用户类型的所有权限重新设置</td></tr></tbody></table><p>permission 的符号模式表:</p><table><thead><tr><th style="text-align:left;">who</th><th style="text-align:center;">用户类型</th><th style="text-align:center;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">r</td><td style="text-align:center;">读</td><td style="text-align:center;">设置为可读权限</td></tr><tr><td style="text-align:left;">w</td><td style="text-align:center;">写</td><td style="text-align:center;">设置为可写权限</td></tr><tr><td style="text-align:left;">x</td><td style="text-align:center;">执行权限</td><td style="text-align:center;">设置为可执行权限</td></tr><tr><td style="text-align:left;">X</td><td style="text-align:center;">特殊执行权限</td><td style="text-align:center;">只有当文件为目录文件，或者其他类型的用户有可执行权限时，才将文件权限设置可执行</td></tr><tr><td style="text-align:left;">s</td><td style="text-align:center;">setuid/gid</td><td style="text-align:center;">当文件被执行时，根据 who 参数指定的用户类型设置文件的 setuid 或者 setgid 权限</td></tr><tr><td style="text-align:left;">t</td><td style="text-align:center;">粘贴位</td><td style="text-align:center;">设置粘贴位，只有超级用户可以设置该位，只有文件所有者 u 可以使用该位</td></tr></tbody></table><h4 id="八进制语法" tabindex="-1"><a class="header-anchor" href="#八进制语法" aria-hidden="true">#</a> 八进制语法</h4><p>chmod 命令可以使用八进制数来指定权限。文件或目录的权限位是由 9 个权限位来控制，每三位为一组，它们分别是文件所有者（User）的读、写、执行，用户组（Group）的读、写、执行以及其它用户（Other）的读、写、执行。历史上，文件权限被放在一个比特掩码中，掩码中指定的比特位设为 1，用来说明一个类具有相应的优先级。</p><table><thead><tr><th style="text-align:left;">#</th><th style="text-align:center;">权限</th><th style="text-align:center;">rwx</th><th style="text-align:center;">二进制</th></tr></thead><tbody><tr><td style="text-align:left;">7</td><td style="text-align:center;">读 + 写 + 执行</td><td style="text-align:center;">rwx</td><td style="text-align:center;">111</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:center;">读 + 写</td><td style="text-align:center;">rw-</td><td style="text-align:center;">110</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:center;">读 + 执行</td><td style="text-align:center;">r-x</td><td style="text-align:center;">101</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:center;">只读</td><td style="text-align:center;">r--</td><td style="text-align:center;">100</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:center;">写 + 执行</td><td style="text-align:center;">-wx</td><td style="text-align:center;">011</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:center;">只写</td><td style="text-align:center;">-w-</td><td style="text-align:center;">010</td></tr><tr><td style="text-align:left;">1</td><td style="text-align:center;">只执行</td><td style="text-align:center;">--x</td><td style="text-align:center;">001</td></tr><tr><td style="text-align:left;">0</td><td style="text-align:center;">无</td><td style="text-align:center;">---</td><td style="text-align:center;">000</td></tr></tbody></table><p>例如， 765 将这样解释：</p><ul><li>所有者的权限用数字表达：属主的那三个权限位的数字加起来的总和。如 rwx ，也就是 4+2+1 ，应该是 7。</li><li>用户组的权限用数字表达：属组的那个权限位数字的相加的总和。如 rw- ，也就是 4+2+0 ，应该是 6。</li><li>其它用户的权限数字表达：其它用户权限位的数字相加的总和。如 r-x ，也就是 4+0+1 ，应该是 5。</li></ul><h4 id="实例-2" tabindex="-1"><a class="header-anchor" href="#实例-2" aria-hidden="true">#</a> 实例</h4><p>将文件 file1.txt 设为所有人皆可读取 :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> ugo+r file1.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将文件 file1.txt 设为所有人皆可读取 :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> a+r file1.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将文件 file1.txt 与 file2.txt 设为该文件拥有者，与其所属同一个群体者可写入，但其他以外的人则不可写入 :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> ug+w,o-w file1.txt file2.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,55),h={href:"http://ex1.py",target:"_blank",rel:"noopener noreferrer"},g=a(`<div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> u+x ex1.py
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将目前目录下的所有文件与子目录皆设为任何人可读取 :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token parameter variable">-R</span> a+r *
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>此外chmod也可以用数字来表示权限如 :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token number">777</span> <span class="token function">file</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>语法为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> abc <span class="token function">file</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="默认权限" tabindex="-1"><a class="header-anchor" href="#默认权限" aria-hidden="true">#</a> 默认权限</h2><h3 id="umask" tabindex="-1"><a class="header-anchor" href="#umask" aria-hidden="true">#</a> umask</h3><ul><li>查看默认权限</li><li>0022 <ul><li>第一位 0 文件特殊权限</li><li>022 文件默认权限</li></ul></li></ul><h3 id="文件权限-1" tabindex="-1"><a class="header-anchor" href="#文件权限-1" aria-hidden="true">#</a> 文件权限</h3><ul><li>默认权限就是文件一创建后就拥有的权限</li><li>文件默认不能建立可执行文件，必须手工赋予执行权限</li><li>文件默认权限最大为 666</li><li>默认权限需要换算成字母再相减</li><li>建立文件之后的默认权限，为 666 减去 umask 值</li></ul><h3 id="目录" tabindex="-1"><a class="header-anchor" href="#目录" aria-hidden="true">#</a> 目录</h3><ul><li>目录默认权限最大为 777</li><li>建立目录之后的默认权限，为 777 减去 umask 值</li></ul><h3 id="修改-umask-值" tabindex="-1"><a class="header-anchor" href="#修改-umask-值" aria-hidden="true">#</a> 修改 umask 值</h3><h4 id="临时修改" tabindex="-1"><a class="header-anchor" href="#临时修改" aria-hidden="true">#</a> 临时修改</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">umask</span> 0002
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="永久修改" tabindex="-1"><a class="header-anchor" href="#永久修改" aria-hidden="true">#</a> 永久修改</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">umask</span> 0002
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="sudo-权限" tabindex="-1"><a class="header-anchor" href="#sudo-权限" aria-hidden="true">#</a> sudo 权限</h2><ul><li>root 本来只有超级管理员可以使用的命令赋予普通用户来使用</li><li>sudo 操作的对象是系统命令</li></ul><h3 id="visudo" tabindex="-1"><a class="header-anchor" href="#visudo" aria-hidden="true">#</a> visudo</h3><ul><li>通过<code>visudo</code>可以由超级用户赋权</li><li>实际修改的是<code>/etc/sudoers</code>文件</li><li>命令必须写绝对路径</li></ul>`,23);function b(x,m){const n=l("ExternalLinkIcon");return d(),i("div",null,[u,t("p",null,[e("为 "),t("a",h,[e("ex1.py"),c(n)]),e(" 文件拥有者增加可执行权限:")]),g])}const f=s(p,[["render",b],["__file","05.文件权限.html.vue"]]);export{f as default};
